export const allCities = [...new Set(universities.map((u) => u.city))].sort((a, b) => a.localeCompare(b, 'ru'));

export const allRegions = [...new Set(universities.map((u) => u.region))].sort((a, b) => a.localeCompare(b, 'ru'));

export const allSpecialties = [
  ...new Set(universities.flatMap((u) => u.specialties)),
].sort((a, b) => a.localeCompare(b, 'ru'));
